import{_ as a,c as s,o as e,U as n}from"./chunks/framework.9QHaLlVJ.js";const g=JSON.parse('{"title":"Shebang","description":null,"frontmatter":{"lang":"zh-CN","title":"Shebang","description":null},"headers":[],"relativePath":"doc/编程语言/Shell/基础/Shebang/Shebang.md","filePath":"packages/doc/src/编程语言/Shell/基础/Shebang/Shebang.md","lastUpdated":1702458087000}'),l={name:"doc/编程语言/Shell/基础/Shebang/Shebang.md"},i=n(`<h1 id="shebang" tabindex="-1">Shebang <a class="header-anchor" href="#shebang" aria-label="Permalink to &quot;Shebang&quot;">​</a></h1><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Linux脚本第一行#!符号可以叫做shebang。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>很早之前,shebang一直都没有正式的中文名称,后来Linux中国翻译组的GOLinux将其翻译为释伴,</span></span>
<span class="line"><span>即&quot;解释伴随行&quot;的简称，同时又是shebang的音译。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="shell第一行组成" tabindex="-1">shell第一行组成 <a class="header-anchor" href="#shell第一行组成" aria-label="Permalink to &quot;shell第一行组成&quot;">​</a></h2><ul><li><strong>#!</strong></li><li><strong>空格</strong></li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>可以有多个</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>解释器路径</strong></li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>必须使用绝对路径，用于指明执行这个脚本的解释器。</span></span>
<span class="line"><span>在直接调用脚本的时候,系统的程序载入器会分析shebang后面的内容,将这些内容作为解释器指令,并调用该指令,</span></span>
<span class="line"><span>将载有shebang的文件路径作为该解释器的参数,执行脚本,从而使脚本文件的调用方式与普通的可执行文件类似.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="作用" tabindex="-1">作用 <a class="header-anchor" href="#作用" aria-label="Permalink to &quot;作用&quot;">​</a></h2><p>由于#符号在许多脚本语言中都是注释标识符,shebang的内容会被这些脚本解释器自动忽略。 在字符不是注释标识符的语言中,例如scheme,解释器也能忽略以#!开头的首行内容,这样就保证了shebang的很好的兼容性。</p><h2 id="用法" tabindex="-1">用法 <a class="header-anchor" href="#用法" aria-label="Permalink to &quot;用法&quot;">​</a></h2><ul><li>如果脚本文件中没有#!这一行,那么执行shell脚本的时候,就会默认使用当前的shell去解释这个脚本(即:$SHELL环境变量)</li><li>如果#!之后的解释程序是一个可执行文件,那么执行这个脚本时,他就会把文件名以及参数一起作为参数传递给那个解释程序去执行</li><li>如果#!指定的解释程序没有可执行权限,就会报错,提示权限被拒绝</li><li>如果#!指定的解释程序不是一个可执行文件,那么指定的解释程序会被忽略,转交给当前shell去执行这个脚本</li><li>如果#!指定的解释程序不存在,就会报错找不到那个目录或文件</li><li>#!之后的解释器路径必须要用绝对路径,它不会自动去$PATH环境变量中寻找解释器</li><li>如果在命令行执行脚本的时候,执行采用某一个解释器去执行,比如bash test.sh这样的命令,那么脚本中的#!一行将被自动忽略</li><li>脚本文件必须要有可执行权限,脚本才会被执行</li></ul><h2 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点&quot;">​</a></h2><p>shebang的好处在于,允许脚本和数据文件充当系统命令,无需在调用的时候由用户指定解释器,从而对用户或者其他程序隐藏了其执行的细节.</p><ul><li>#!/bin/sh 使用sh,即Bourne shell或其他兼容shell执行脚本</li><li>#!/bin/csh 使用csh,即C shell执行</li><li>#!/usr/bin/perl -w 使用带警告的perl执行</li><li>#!/usr/bin/python -0 使用具有代码优化的python执行</li><li>#!/usr/bin/php 使用php的命令行解释器执行</li></ul>`,14),t=[i];function p(h,r,o,c,d,b){return e(),s("div",null,t)}const m=a(l,[["render",p]]);export{g as __pageData,m as default};
